write_files.src/payments/settlement.ts:
import { enqueueSettlementRetry } from './retry-queue';

export async function settle(paymentId: string, idempotencyKey: string): Promise<void> {
  try {
    await provider.capture(paymentId, { idempotencyKey });
  } catch (error) {
    await enqueueSettlementRetry({ paymentId, idempotencyKey, attempt: 1 });
  }
}

write_files.src/payments/retry-queue.ts:
export async function enqueueSettlementRetry(job: { paymentId: string; idempotencyKey: string; attempt: number }): Promise<void> {
  const delaySeconds = 5 * (2 ** job.attempt);
  await retryQueue.enqueue(job, { delaySeconds, maxAttempts: 5 });
}

write_files.tests/payments/settlement-idempotency.te:
test('preserves the idempotency key in a retry job', async () => {
  await settle('payment-1', 'settlement-key-1');
  expect(retryQueue.lastJob.idempotencyKey).toBe('settlement-key-1');
});
